head.script:
//==================================================================================================================
// id       : fi_203_01_08b
// 이름     : 총계정원장집계표
// 경로     : 회계/재무회계/일반회계/원장관리/
// 작 성 자 : 오영재
// 작 업 일 : 2025-12-23
//            2026-04-24 김용욱 : 발생월 체크박스 수정 / 팝업 정리 외
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================

scwin.today          = $c.date.getServerDateTime("yyyyMMdd");
scwin.vLoginCoCd     = $c.gus.cfIsNull( $c.data.getMemInfo("coCd"         ) ) ? '' : $c.data.getMemInfo("coCd"); // 소속 자회사  
scwin.vLoginCoClsCd  = $c.gus.cfIsNull( $c.data.getMemInfo("coClsCd"      ) ) ? '' : $c.data.getMemInfo("coClsCd");
scwin.vUserHomeClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("userHomeClsCd") ) ? '' : $c.data.getMemInfo("userHomeClsCd");
scwin.vUserId        = $c.gus.cfIsNull( $c.data.getMemInfo("userId"       ) ) ? '' : $c.data.getMemInfo("userId");
scwin.privAdmin      = $c.gus.cfIsNull( $c.data.getMemInfo("privAdmin"    ) ) ? '' : $c.data.getMemInfo("privAdmin");

scwin.isSubCompany   = false;

scwin.quantityOfRows = "1000";
scwin.pageNumber     = "1";

//hidden
scwin.txtCoClsCd         = "";
scwin.txt_pageNumber     = "";
scwin.txt_quantityOfRows = "";

scwin.onpageload = function() {
    console.log("====== onpageload ==================v 1.01");

};

scwin.onUdcCompleted = function() {
    console.log("  ==--== onUdcCompleted");

    // 2025-10-14 : 작성일자 포커스 위치 이동
    $p.setTimeout(function () {
        scwin.f_Setting();
	    scwin.f_setCompanyInfo();

        // paging 처리 관련
        btn_addSearch.hide();
        bSearch.hide();
        lAddRow.hide();
        bSearch2.hide();

        scwin.txt_pageNumber = scwin.pageNumber;
        scwin.txt_quantityOfRows  = scwin.quantityOfRows;

        ed_srchAcctDeptCd.setValue("00000");
        ed_srchAcctDeptNm.setValue("전사");

        scwin.f_CloseYm();  // 마감년월
        scwin.f_empNo();    // 세무조사 관련
    }, { "delay": 50 });
};


// @@ ====== 준비 ============================================================================== //


//-------------------------------------------------------------------------
// 기본셋팅
//------------------------------------------------------------------------- 
scwin.f_Setting = function() {   
    ed_qryYm.setValue( scwin.today.substring(0,6) );
    ed_acctCdSt     .options.hidVal = dma_search.get("acctCdSt");
    ed_acctCdEnd    .options.hidVal = dma_search.get("acctCdEnd");
    ed_acctDeptCdSt .options.hidVal = dma_search.get("acctDeptCdSt");
    ed_acctDeptCdEnd.options.hidVal = dma_search.get("acctDeptCdEnd");
    ed_clntNo       .options.hidVal = dma_search.get("clntNo")
    ed_crn          .options.hidVal = dma_search.get("crn");
    rd_type.setValue("2");
    lc_qryCond.setSelectedIndex(0);
    ed_qryYm.focus();
    scwin.f_QryCond();  
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = async function() {   
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD )  {  
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue( scwin.vLoginCoCd );

    const result = await scwin.f_PopUpCompanyInfo('T'); 
    scwin.udc_coCd_cb(result);
    if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
    }else {
        $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
    }  
};


//-------------------------------------------------------------------------
// 마지막 마감년월를 구한다.
//-------------------------------------------------------------------------	
scwin.f_CloseYm = function() {
    let ebcId = "ManagementProfitAndLossEBC";
    let queryId = "retrieveManagementProfitAndLossCloseYm";
        //ds_closeYm.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd="+ebcId +"&queryId="+queryId ;

    //ds_closeYm.Reset();
    sbm_closeYm.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd="+ebcId +"&queryId="+queryId ;
    $c.sbm.execute( sbm_closeYm );
};

scwin.sbm_closeYm_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }

    ed_compYm.setValue( ds_closeYm.getCellData(0, "col1") );
};


//-------------------------------------------------------------------------
// FI624 (세무조사 아이디) 조회
//   증빙관리권한 : 세무조사시에만 사용하는 계정
//-------------------------------------------------------------------------
scwin.f_empNo = function() {
    console.log("===== f_empNo - FI624 (세무조사 아이디) 조회");

    let grp_cd ="FI624";  //세무조사 아이디
    let pCode = scwin.vUserId ;

    // SELECT 절 
    let param1 = 
      " CD      as COL1 "
    + ",CD_NM 	as COL2 "
    + ",'' 		as COL3 "
    + ",'' 		as COL4 "
    + ",'' 		as COL5 "
    + ",'' 		as COL6 "
    + ",''      as COL7 "
    + ",''      as COL8 "
    + ",''      as COL9 "
    + ",''      as COL10"
    ;

    // 대상테이블 	
    let param2 = " TB_ZZ002 ";

    // 조건절
    let param3 = 
          " AND GRP_CD = '" + grp_cd + "'" 
        + " AND USE_YN = '1' "
        //+ " AND CD_NM LIKE '"+pCode+"'% || '%'"
        + " AND CD_NM  = '" + pCode + "' " 
        ;

    let param4 =  "CD";

    sbm_empNo.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    $c.sbm.execute(sbm_empNo);
};

scwin.sbm_empNo_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }

    // e.responseJSON.GAUCE
    if ( ds_empNo.getRowCount() > 0 ) {
        ed_qryYm.setValue("201501");
        ed_compYm.setValue("201501");
        ozprint.setStyle("display", "none");
    } else {
        ozprint.setStyle("display", "block");
    }
};


// @@ ====== 조회 ============================================================================== //

// 초기화 버튼 (히든 처리됨)
scwin.btn_reset_onclick = function (e) {
    $c.gus.cfInitObjects(tbl_search, null);
    scwin.onUdcCompleted();
};

//-------------------------------------------------------------------------
// 조회(총계정원장집계표)
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {  

    let ret;

    ret = await $c.gus.cfValidate([ed_coCd, ed_qryYm, ed_acctCdSt, ed_acctCdEnd,ed_acctDeptCdSt,ed_acctDeptCdEnd,ed_crn]);
    if (!ret)
    return false;

    if(!scwin.f_HiddenCheck(ed_acctCdSt,"계정From")) return false;
    if(!scwin.f_HiddenCheck(ed_acctCdEnd,"계정To")) return false;
    if(!scwin.f_HiddenCheck(ed_acctDeptCdSt,"귀속부서From")) return false;
    if(!scwin.f_HiddenCheck(ed_acctDeptCdEnd,"귀속부서To")) return false;

    if (!scwin.f_BetweenCheck(ed_acctCdSt.getValue().trim(), ed_acctCdEnd.getValue().trim())){
        await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_057,"계정코드To","계정코드From"));
        ed_acctCdSt.focus();
        return false;
    }

    scwin.f_QryCond();
    //gr_total1.ReDraw = "False";
    //gr_total2.ReDraw = "False";
    //gr_total3.ReDraw = "False";


    if(bSearch2._getVisible() == false){
        bSearch2.show();
    }
    scwin.txt_pageNumber  = scwin.pageNumber;
    scwin.txt_quantityOfRows = scwin.quantityOfRows;

    //ds_search.UseChangeInfo = false;
    //tr_search.Action="/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerTabulationCMD.do";
    //tr_search.post();

    let chkFilterYn = "";
    if(cbx_filterYn.getValue() == '1'){
        chkFilterYn = "1";   		
    }
    else{
        chkFilterYn = "0";   		
    }

    if(ed_qryYm.getValue() <= ed_compYm.getValue()) // 비교년월 회계년월 체크
    {
        // 세무조사 관련 일자 제한	
        if (ds_empNo.getRowCount() > 0) {
            if(ed_qryYm.getValue() !="" && ed_compYm.getValue() !="" ){
                if(ed_qryYm.getValue() == "201501" && ed_compYm.getValue() == "201501"){

                }else{
                    await $c.win.alert("비교년월이 회계년월보다 크거나  같을수 없습니다.");
                    return false;
                }
            }
        }else{
            $c.win.alert("비교년월이 회계년월보다 크거나  같을수 없습니다.");
            return false;
        }
    }


    // 세무조사 관련 일자 제한	
    if (ds_empNo.getRowCount() > 0) {
        if(ed_qryYm.getValue() !="" && ed_compYm.getValue() !="" ){
            if(ed_qryYm.getValue().substr(0,4) <="2013" || ed_compYm.getValue().substr(0,4) >= "2019"){
                await $c.win.alert("2014~2018년 이외의 조회 권한이 없습니다.");
                return false;
            }
        }
    }

    let qryDate  = new Date(ed_qryYm.getValue().substring(0, 4), ed_qryYm.getValue().substring(4, 6), 0);
    let qryBfLast = new Date(qryDate.getFullYear(), qryDate.getMonth());

    let qryBfMm = new Date(qryBfLast - 1) ; 	
    let gryMonth = 	new Date(qryBfMm.getFullYear(), qryBfMm.getMonth());
    gryMonth = gryMonth.format('YYYYMM');	

    if(ed_acctCdSt.getValue() != '' && ed_acctCdSt.getValue().trim().substring(0,1) != '1' && ed_acctCdSt.getValue().trim().substring(0,1) != '2'
        && (gryMonth != ed_compYm.getValue()) )
    {	
        await $c.win.alert("자산, 부채 계정외에는 비교년월과 회계년월 차이가 1개월을 초과 할 수 없습니다.");
        return false;
    }

    // let strParam = "?qryYm="              	+ ed_qryYm.getValue()
    //                 + "&acctCdSt="         	+ ed_acctCdSt.getValue()
    //                 + "&acctCdEnd="         	+ ed_acctCdEnd.getValue()
    //                 + "&acctDeptCdSt="         + ed_acctDeptCdSt.getValue()
    //                 + "&acctDeptCdEnd="        + ed_acctDeptCdEnd.getValue()
    //                 + "&qryCond="         		+ lc_qryCond.getValue()          
    //                 + "&type="					+ rd_type.getValue()
    //                 + "&clntNo="          		+ ed_clntNo.getValue()
    //                 + "&crn="					+ ed_crn.getValue()			
    //                 + "&coCd="         		+ ed_coCd.getValue()
    //                 + "&coClsCd="             	+ scwin.txtCoClsCd
    //                 + "&pageNumber="        	+ scwin.txt_pageNumber
    //                 + "&quantityOfRows="		+ scwin.txt_quantityOfRows
    //                 + "&chkFilterYn="			+ chkFilterYn.getValue()
    //                 + "&compYm="         		+ ed_compYm.getValue()
    //                 + "&srchAcctDeptCd="		+ ed_srchAcctDeptCd.getValue()
    //                 + "&bizDomCd="				+ ed_BizDomCd.getValue() 	                 
    //                 ;

    dma_search.set("qryYm",            ed_qryYm.getValue());
    dma_search.set("acctCdSt",         ed_acctCdSt.getValue());
    dma_search.set("acctCdEnd",        ed_acctCdEnd.getValue());
    dma_search.set("acctDeptCdSt",     ed_acctDeptCdSt.getValue());
    dma_search.set("acctDeptCdEnd",    ed_acctDeptCdEnd.getValue());
    dma_search.set("crn",              ed_crn.getValue());
    dma_search.set("clntNo",           ed_clntNo.getValue());
    dma_search.set("qryCond",          lc_qryCond.getValue());
    dma_search.set("type",             rd_type.getValue());
    dma_search.set("coCd",             ed_coCd.getValue());
    dma_search.set("coClsCd",          scwin.txtCoClsCd);
    dma_search.set("chkFilterYn",      chkFilterYn);
    dma_search.set("quantityOfRows",   scwin.txt_quantityOfRows);
    dma_search.set("pageNumber",       scwin.txt_pageNumber);
    dma_search.set("compYm",           ed_compYm.getValue());
    dma_search.set("srchAcctDeptCd",   ed_srchAcctDeptCd.getValue());
    dma_search.set("bizDomCd",         ed_BizDomCd.getValue());


    //ds_total.DataID = "/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerTabulationCMD.do" + strParam; 
    //ds_total.Reset();
    //sbm_retrieve.action = "/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerTabulationCMD.do";
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회(총계정원장집계표) submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function(e) {
    //let temp = ds_total.RealCount(1,ds_total.CountRow);
	//cfShowTotalRows(totalRows, temp);

    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }

    const rowCount = ds_total.getRowCount();
    const totRowCountInfo = {"1" : ed_totalRows,"2" : ed_totalRows2,"3": ed_totalRows3};
    totRowCountInfo[lc_qryCond.getValue()].setValue(rowCount);

    // SORT 처리 
    const sortIndexInfo = {"1":"acctCd acctDeptCd mgntClntNo" , "2" : "acctDeptCd acctCd mgntClntNo", "3" : "mgntClntNo acctCd acctDeptCd"};
    ds_total.multisort({sortIndex : sortIndexInfo[lc_qryCond.getValue()] , sortOrder : "1 1 1"})

	if( rowCount == 0 ){
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		//속도개선을 위한 추가조회(2013.03.20 이석건)
		$c.gus.cfDisableObjects([btn_addSearch]);
		bSearch2.hide();
	} else {
		//조회 완료후 추가조회
		bSearch2.hide();
		//f_Retrieve2();
	}
	$c.gus.cfEnableObjects([btn_addSearch]);    
};

//-------------------------------------------------------------------------
// 속도개선을 위한 추가조회 (총계정원장집계표)
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = function() {  
    //PAGE 계산 후 다시 조회 해서 ds_total에 데이터를 계속 add 한다.
    let pagenum = parseInt(scwin.txt_pageNumber)+1;
    let quantityOfRows2 = parseInt(scwin.txt_quantityOfRows);

    scwin.txt_pageNumber = pagenum;
    scwin.txt_quantityOfRows = quantityOfRows2;

    if(bSearch._getVisible() == false){
        bSearch.show();
    }

    //ds_search.UseChangeInfo = false;
    //tr_search2.Action="/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerTabulationCMD.do";
    //tr_search2.post();

    let chkFilterYn = "";
    if(cbx_filterYn.getValue() == '1'){
        chkFilterYn = "1";   		
    }
    else{
        chkFilterYn = "0";   		
    }

    // let strParam = "?qryYm="              	+ ed_qryYm.getValue()
    //                 + "&acctCdSt="         	+ ed_acctCdSt.getValue()
    //                 + "&acctCdEnd="         	+ ed_acctCdEnd.getValue()
    //                 + "&acctDeptCdSt="         + ed_acctDeptCdSt.getValue()
    //                 + "&acctDeptCdEnd="        + ed_acctDeptCdEnd.getValue()
    //                 + "&qryCond="         		+ lc_qryCond.getValue()     
    //                 + "&type="					+ rd_type.getValue()
    //                 + "&clntNo="          		+ ed_clntNo.getValue()
    //                 + "&crn="					+ ed_crn.getValue()
    //                 + "&coCd="         		+ ed_coCd.getValue()  		
    //                 + "&coClsCd="             	+ scwin.txtCoClsCd
    //                 + "&pageNumber="        	+ scwin.txt_pageNumber
    //                 + "&quantityOfRows="		+ scwin.txt_quantityOfRows
    //                 + "&chkFilterYn="			+ chkFilterYngetValue()
    //                 + "&compYm="         		+ ed_compYm.getValue()
    //                 + "&srchAcctDeptCd="		+ ed_srchAcctDeptCd.getValue()
    //                 + "&bizDomCd="				+ ed_BizDomCd.getValue()
    //                 ;

    dma_search.set("qryYm",            ed_qryYm.getValue());
    dma_search.set("acctCdSt",         ed_acctCdSt.getValue());
    dma_search.set("acctCdEnd",        ed_acctCdEnd.getValue());
    dma_search.set("acctDeptCdSt",     ed_acctDeptCdSt.getValue());
    dma_search.set("acctDeptCdEnd",    ed_acctDeptCdEnd.getValue());
    dma_search.set("crn",              ed_crn.getValue());
    dma_search.set("clntNo",           ed_clntNo.getValue());
    dma_search.set("qryCond",          lc_qryCond.getValue());
    dma_search.set("type",             rd_type.getValue());
    dma_search.set("coCd",             ed_coCd.getValue());
    dma_search.set("coClsCd",          scwin.txtCoClsCd);
    dma_search.set("chkFilterYn",      chkFilterYn);
    dma_search.set("quantityOfRows",   scwin.txt_quantityOfRows);
    dma_search.set("pageNumber",       scwin.txt_pageNumber);
    dma_search.set("compYm",           ed_compYm.getValue());
    dma_search.set("srchAcctDeptCd",   ed_srchAcctDeptCd.getValue());
    dma_search.set("bizDomCd",         ed_BizDomCd.getValue());

    //ds_total2.DataID = "/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerTabulationCMD.do" + strParam; 
    //ds_total2.Reset();
    //sbm_retrieve2.action = "/ac.fi.gnrlaccount.ledgmgnt.RetrieveTotalAccountLedgerTabulationCMD.do";
    $c.sbm.execute(sbm_retrieve2);

    $c.gus.cfDisableObjects([btn_addSearch]);
};

//-------------------------------------------------------------------------
// 속도개선을 위한 추가조회 (총계정원장집계표) submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve2_submitdone = function(e) {
    let rowCnt = ds_total2.getRowCount();
	if ( rowCnt > 0 ) {
		//ds_total.ImportData(ds_total2.ExportData(1,rowCnt,false));
        ds_total.ImportData(ds_total2.ExportData(1, ds_total2.getRowCount(), false));
		ds_total.modifyAllStatus("R");
	}
	lAddRow.hide();

    //cfShowTotalRows(totalRows, ds_total.CountRow);  
    ed_totalRows.setValue( ds_total.getRowCount() );
    ds_total2.removeAll(); 

    if( rowCnt == 0){
        $c.gus.cfDisableObjects([btn_addSearch]);
        bSearch.hide();
    }
    else
    {
	   	//recursive 조회
	   	//f_Retrieve2();
	   	bSearch.show();
    	$c.gus.cfDisableObjects([btn_addSearch]);
    }
};


// @@ ====== 그리드 / DS ======================================================================= //

scwin.gr_total1_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId=="slipNo"){
		$c.gus.cfShowSlipInfo(ds_total.getCellData(rowIndex,"slipNo"));
	}
};

scwin.gr_total2_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId=="slipNo"){
		$c.gus.cfShowSlipInfo(ds_total.getCellData(rowIndex,"slipNo"));
	}
};

scwin.gr_total3_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId=="slipNo"){
		$c.gus.cfShowSlipInfo(ds_total.getCellData(rowIndex,"slipNo"));
	}
};

// language=JavaScript for=ds_total2 event=OnLoadProcess(rowCnt)>
scwin.ds_total2_ondataload = function () {
    let rowCnt = ds_total2.getRowCount();
    if ( rowCnt > 0 ) {
		// 병합중 메세지 
		lAddRow.show();
		// 조회 메시지
	   	bSearch.hide();
   	}
};


// @@ ====== 팝업 ============================================================================== //

//-------------------------------------------------------------------------
// 회사코드 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = async function (e) {
    const result = await scwin.f_PopUpCompanyInfo('F');
    scwin.udc_coCd_cb(result);
};

//-------------------------------------------------------------------------
// 사업영역 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_BizDomCd_onclickEvent = function (e) {
    scwin.f_openPopUp('8','F');
};

