//-------------------------------------------------------------------------
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openPopUp('4','F');
};

//-------------------------------------------------------------------------
// 부서From 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_acctDeptCdSt_onclickEvent = function (e) {
    scwin.acctPopUp('3','ed_acctDeptCdSt');
};

//-------------------------------------------------------------------------
