//-------------------------------------------------------------------------
// function name : acctPopUp
// function desc : 부서, 계정 between 팝업용 연동
// function Parameter : null
//-------------------------------------------------------------------------
scwin.acctPopUp = function(flag, check) {    
    scwin.f_openPopUp(flag, 'F');

    if(check == "ed_acctDeptCdSt"){
        if(ed_acctDeptCdEnd.getValue() == ""){
            ed_acctDeptCdEnd.setValue( ed_acctDeptCdSt.getValue() );
            scwin.f_checkPopEd(ed_acctDeptCdEnd,ed_acctDeptNmEnd,'5');
        }
    }

    if(check == "ed_acctDeptCdEnd"){
        if(ed_acctDeptCdSt.getValue() == ""){
            ed_acctDeptCdSt.setValue( ed_acctDeptCdEnd.getValue() );
            scwin.f_checkPopEd(ed_acctDeptCdSt,ed_acctDeptNmSt,'3');
        }
    }

    if (check == "ed_acctCdSt"){
        if(ed_acctCdEnd.getValue() == ""){
            ed_acctCdEnd.setValue(ed_acctCdSt.getValue() );
            scwin.f_checkPopEd(ed_acctCdEnd,ed_acctCdEndNm,'2');
        }
    }

    if (check == "ed_acctCdEnd"){
        if(ed_acctCdSt.getValue() == ""){
            ed_acctCdSt.setValue( ed_acctCdEnd.getValue() );
            scwin.f_checkPopEd(ed_acctCdSt,ed_acctCdStNm,'1');
        }
    }
};


//-------------------------------------------------------------------------
// 팝업 @@
//-------------------------------------------------------------------------
scwin.f_openPopUp = function(flag,check) {

	let qryYear = ed_qryYm.getValue().trim().substring(0,4);
    let temp;

    //var rtnList = new Array();
    switch (flag)
	{
		case '1':  
            // 계정조회
            temp = "T,,";  
            udc_acctCdSt.setSelectId("retrieveAcctCdInfo");
            udc_acctCdSt.cfCommonPopUp(scwin.udc_acctCdSt_cb,ed_acctCdSt.getValue().trim(),ed_acctCdStNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 


        break;

	    case '2':
            // 계정조회
            temp = "T,,"; 
            udc_acctCdEnd.setSelectId("retrieveAcctCdInfo");
            udc_acctCdEnd.cfCommonPopUp(scwin.udc_acctCdEnd_cb,ed_acctCdEnd.getValue().trim(),ed_acctCdEndNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 

	    break;    

	    case '3':
	        // 부서  
		    temp = ","+ed_coCd.getValue()+","+scwin.txtCoClsCd+",0";

            udc_acctDeptCdSt.setSelectId("retrieveAcctDeptCdInfo10");
	 	    udc_acctDeptCdSt.cfCommonPopUp(scwin.udc_acctDeptCdSt_cb,ed_acctDeptCdSt.getValue().trim(),ed_acctDeptNmSt.getValue(),check,null,null,null,null,temp,null,null,null,null,null,null,null,null,null,qryYear); 

		break;

		case '5':
	        // 부서 
	        temp = ","+ed_coCd.getValue()+","+scwin.txtCoClsCd+",0";

            udc_acctDeptCdEnd.setSelectId("retrieveAcctDeptCdInfo10");
	 	    udc_acctDeptCdEnd.cfCommonPopUp(scwin.udc_acctDeptCdEnd_cb,ed_acctDeptCdEnd.getValue().trim(),ed_acctDeptNmEnd.getValue(),check,null,null,null,null,temp,null,null,null,null,null,null,null,null,null,qryYear); 

		break;

		case '4':
            // 거래처
            temp=",,,"+ed_coCd.getValue(); 

            udc_clntNo.setSelectId("retrieveClntList2");
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_cb,ed_clntNo.getValue().trim(),ed_clntNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 

		break;

	    case '6':
            // 사업자번호 

            udc_crn.setSelectId("retrieveCrnInfo");
            temp = "";

            if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {   // 자회사인 경우에만  회사코드 check
                udc_crn.setSelectId("retrieveCrnClntInfo");
                temp=","+ed_coCd.getValue();
            }

            udc_crn.cfCommonPopUp(scwin.udc_crn_cb,ed_crn.getValue().trim(),ed_busiNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 

	    break;

		 case '7':
            // 지사 
            udc_srchAcctDeptCd.setSelectId("retrieveAcctDeptCdInfo");
            temp = "";

            if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {   // 자회사인 경우에만  회사코드 check
                udc_srchAcctDeptCd.setSelectId("retrieveAcctDeptCdInfo");
                temp=","+ed_coCd.getValue();
            }

            udc_srchAcctDeptCd.cfCommonPopUp(scwin.udc_srchAcctDeptCd_cb,ed_crn.getValue().trim(),ed_busiNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 
            //scwin.f_resultPopEd(ed_srchAcctDeptCd, ed_srchAcctDeptNm, rtnList);
	    break;

		case '8':
            // 사업영역
            udc_BizDomCd.setSelectId("retrieveBizDomCdInfo");
            temp = "";

            if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU )  {   // 자회사인 경우에만  회사코드 check
                udc_BizDomCd.setSelectId("retrieveBizDomCdInfo");
                temp = ","+ ed_coCd.getValue();
            }	

            udc_BizDomCd.cfCommonPopUp(scwin.udc_BizDomCd_cb , ed_BizDomCd.getValue().trim(),ed_BizDomNm.getValue(),check,null,null,null,null,temp,null,null,null,null); 

	    break;	    

   		default:
		break; 
    }
};



