//-------------------------------------------------------------------------
// 히든값체크
//-------------------------------------------------------------------------
scwin.f_HiddenCheck = function(str,msg) {

    if(str.getValue().trim()=="") return true;
    if (str.getValue().trim() != str.options.hidVal){
        $c.gus.cfAlertMsg(MSG_CM_ERR_038,[msg]);
        //str.SelectAll = "true";
        str.focus();
        return false;
    }else{
        return true;
    }
}

//-------------------------------------------------------------------------
// 숫자차이체크
//-------------------------------------------------------------------------
scwin.f_BetweenCheck = function(str1,str2) {
    try {
        if((str1==""&& str2!="" )||(str1!=""&&str2 =="")){
            return false;
        }
        if(parseInt(str2)-parseInt(str1)<0){
            return false;
        }
        return true;
    } catch (e) {
        return false;
    }
};


