//-------------------------------------------------------------------------
// 총계정원장집계발행 
//-------------------------------------------------------------------------
scwin.f_OzReport = function() {

    let odiName = "";
    let reportName = "";  

     // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)                           
	if( lc_qryCond.getValue() == "1") {
        odiName = "fi_203_01_08p";
    } else if( lc_qryCond.getValue() == "2" ){
        odiName = "fi_203_01_08p_1";
    } else if( lc_qryCond.getValue()=="3" ){
        odiName = "fi_203_01_08p_2";
	}
    reportName  = `/ac/fi/gnrlaccount/ledgmgnt/${odiName}.ozr`;

	if (reportName == "") {
		return;
	}

	let printMode   = chb_printCheck.getValue()   == "1" ? 'view' : 'silent';	// 인쇄옵션처리
	let previewMode = chb_previewCheck.getValue() == "1";					    // 미리보기처리

    let odiParam = {
          "qryYm"          : ed_qryYm         .getValue().trim()       
        , "acctCdSt"       : ed_acctCdSt      .getValue().trim()       
        , "acctCdEnd"      : ed_acctCdEnd     .getValue().trim()       
        , "acctDeptCdSt"   : ed_acctDeptCdSt  .getValue().trim()       
        , "acctDeptCdEnd"  : ed_acctDeptCdEnd .getValue().trim()       
        , "qryCond"        : lc_qryCond       .getValue().trim()       
        , "acctDeptNmSt"   : ed_acctDeptNmSt  .getValue().trim()       
        , "acctDeptNmEnd"  : ed_acctDeptNmEnd .getValue().trim()       
        , "clntNo"         : ed_clntNo        .getValue().trim()       
        , "clntNm"         : ed_clntNm        .getValue().trim()       
        , "crn"            : ed_crn           .getValue().trim()       
        , "coCd"           : ed_coCd          .getValue().trim()       
        , "coClsCd"        : scwin.txtCoClsCd            .trim()       
        , "srchAcctDeptCd" : ed_srchAcctDeptCd.getValue().trim()       
        , "bizDomCd"       : ed_BizDomCd      .getValue().trim()       
        , "compYm"         : ed_compYm        .getValue().trim()       
        , "type"           : rd_type          .getValue()  
        , "acctDeptCd"     : ed_acctDeptCdSt  .getValue().trim()       
    }

	if (previewMode) {	//미리보기시
		let data = {
			"reportName": reportName,
			"odiParam": odiParam,
			"viewerParam": {
				"useprogressbar": true, // 프로그레스바 쓸지 말지
				"printcommand": true,
				"zoom": 100, // 배율 설정
                "mode" : "preview",
			},
			"formParam": {
				"odiName": odiName
			}
            ,odiName
		};
		let opts = {
			"type": 'viewer', // viewer, print, download
			"printMode": "view",
			"exportFilename": "fi_203_01_08b",
			"exportPath": 'C:\\OZExport',
			"exportFormat": 'pdf',
            "exportMode" : 'view'
		};

		$c.ext.openOzReport(data, opts);
	} else {
        if ( printMode == "view" ) {
            let data = {
                "reportName": reportName,
                "odiParam": odiParam,
                "viewerParam": {
                    "useprogressbar": true,
                    "viewer": 100
                },
                "formParam": {
                    "odiName": odiName
                }
            };
            let opts = {
                "type": "viewer", // viewer, print, download
                "printMode": "view", // silent, view
                "exportFilename": "fi_203_01_08b",
                "exportPath": "C:\\OZExport",
                "exportFormat": "pdf",
                "exportMode" : 'view'
            };
            $c.ext.printOzReport(data, opts);
        } else {
            let data = {
                "reportName": reportName,
                "odiParam": odiParam,
                "viewerParam": {
                    "useprogressbar": true,
                    "viewer": 100
                },
                "formParam": {
                    "odiName": odiName
                }
                ,odiName
            };
            let opts = {
                "type": 'print',
                "printMode": printMode
            };
            let saveOptions = {
            };            
            $c.ext.downloadOzReport(data, saveOptions);
        }
	}
};


